  const floorOptions = getOrderedFloors(project);
  const totalRise = stairTotalRise(stair);
  const totalRun = stairRun(stair);
  const directionAngle = stair.direction?.angle ?? 0;

  return (
    <div>
      <div className={styles.title}>Stair</div>
