  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createProject } from '@/domain/models';
  3→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
  4→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
  5→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  6→import { clampWallOpeningOffset, wallLength } from '@/geometry/wallGeometry';
  7→
  8→const ProjectContext = createContext(null);
  9→const HISTORY_LIMIT = 100;
 10→
 11→function snapshotProject(project) {
 12→  return JSON.stringify(project);
 13→}
 14→
 15→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 16→  const nextSnapshot = snapshotProject(nextProject);
 17→  const history = recordHistory
 18→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 19→    : state.history;
 20→
 21→  return {
 22→    ...state,
 23→    history,
 24→    future: recordHistory ? [] : state.future,
 25→    project: nextProject,
 26→    isDirty: nextSnapshot !== state.savedSnapshot,
 27→  };
 28→}
 29→
 30→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
 31→  const nextFloors = state.project.floors.map((floor) => (
 32→    floor.id === floorId ? updater(floor) : floor
 33→  ));
 34→
 35→  return applyProjectUpdate(state, {
 36→    ...state.project,
 37→    updatedAt: new Date().toISOString(),
 38→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
 39→  }, recordHistory);
 40→}
 41→
 42→function replaceFloors(state, floors, recordHistory = true) {
 43→  return applyProjectUpdate(state, {
 44→    ...state.project,
 45→    updatedAt: new Date().toISOString(),
 46→    floors: sortFloors(floors),
 47→  }, recordHistory);
 48→}
 49→
 50→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
 51→  return {
 52→    ...project,
 53→    floors: project.floors.map((floor) => ({
 54→      ...floor,
 55→      stairs: (floor.stairs || []).map((stair) => ({
 56→        ...stair,
 57→        floorRelation: {
 58→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
 59→            ? fallbackFloorId
 60→            : (stair.floorRelation?.fromFloorId ?? floor.id),
 61→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
 62→            ? fallbackFloorId
 63→            : (stair.floorRelation?.toFloorId ?? floor.id),
 64→        },
 65→      })),
 66→    })),
 67→    sheets: (project.sheets || []).map((sheet) => ({
 68→      ...sheet,
 69→      viewports: (sheet.viewports || []).map((viewport) => ({
 70→        ...viewport,
 71→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
 72→          ? fallbackFloorId
 73→          : viewport.sourceFloorId,
 74→        sourceRefId: viewport.sourceFloorId === deletedFloorId
 75→          ? null
 76→          : viewport.sourceRefId,
 77→      })),
 78→    })),
 79→  };
 80→}
 81→
 82→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 83→  const nextWall = { ...existingWall, ...wallUpdate };
 84→
 85→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 86→    nextWall.startAttachment = null;
 87→  }
 88→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 89→    nextWall.endAttachment = null;
 90→  }
 91→
 92→  return syncWallAttachmentPoints(nextWall, columns);
 93→}
 94→
 95→function clampWallMountedOpenings(openings, wallId, nextWallLength) {
 96→  return openings.map((opening) => {
 97→    if (opening.wallId !== wallId) return opening;
 98→
 99→    const nextOffset = clampWallOpeningOffset(nextWallLength, opening.width, opening.offset);
100→    return nextOffset === opening.offset ? opening : { ...opening, offset: nextOffset };
101→  });
102→}
