630→export function useProject() {
631→  const ctx = useContext(ProjectContext);
632→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
633→  const { state, dispatch } = ctx;
634→
635→  const duplicateFloor = (floorId) => {
636→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
637→    return floor ? createDuplicatedFloor(floor) : null;
638→  };
639→
640→  return {
641→    project: state.project,
642→    isDirty: state.isDirty,
643→    lastSavedAt: state.lastSavedAt,
644→    canUndo: state.history.length > 0,
645→    canRedo: state.future.length > 0,
646→    dispatch,
647→    duplicateFloor,
648→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
649→  };
