 87→            }
 88→          : null,
 89→      };
 90→
 91→    case 'UPDATE_TOOL_STATE':
 92→      return {
 93→        ...state,
 94→        toolState: { ...state.toolState, ...action.payload },
 95→      };
 96→
 97→    case 'SET_VIEWPORT':
 98→      return {
 99→        ...state,
100→        modelViewport: state.workspaceMode === 'model' ? { ...action.viewport } : state.modelViewport,
101→        sheetViewport: state.workspaceMode === 'sheet' ? { ...action.viewport } : state.sheetViewport,
102→        viewport: { ...action.viewport },
103→      };
104→
105→    case 'PAN':
